// =============================================
// Validar y Transformar - Tiempos por Seccion
// Recibe datos del webhook (archivo subido)
// =============================================

const allItems = $input.all();

try {

// --- Obtener nombre del archivo ---
let fileName = 'upload.xls';
try {
  const binaryData = $('Recibir Archivo').first().binary;
  if (binaryData && binaryData.data && binaryData.data.fileName) {
    fileName = binaryData.data.fileName;
  }
} catch(e) { /* keep default */ }

// --- DETECTAR COLUMNAS ---
const firstJson = allItems[0].json;
let getCol;
let repKeysLen = 10;

if ('row' in firstJson && Array.isArray(firstJson.row)) {
  getCol = (item, idx) => item.json.row ? item.json.row[idx] : undefined;
  repKeysLen = 10;
} else {
  let maxKeys = 0;
  let repKeys = [];
  for (let i = 0; i < Math.min(allItems.length, 30); i++) {
    const keys = Object.keys(allItems[i].json).filter(k => k !== 'row_number');
    if (keys.length > maxKeys) { maxKeys = keys.length; repKeys = [...keys]; }
  }
  if (maxKeys >= 7) {
    repKeys.sort((a, b) => {
      const nA = Number(a); const nB = Number(b);
      if (!isNaN(nA) && !isNaN(nB)) return nA - nB;
      const mA = a.match(/(\d+)/); const mB = b.match(/(\d+)/);
      if (mA && mB) return parseInt(mA[1]) - parseInt(mB[1]);
      return a.localeCompare(b);
    });
    getCol = (item, idx) => idx < repKeys.length ? item.json[repKeys[idx]] : undefined;
    repKeysLen = repKeys.length;
  } else {
    return [{ json: { valid: false, errorMessage: 'Estructura invalida: solo ' + maxKeys + ' columnas detectadas en ' + fileName } }];
  }
}

// --- Funciones auxiliares ---
function esc(s) {
  return String(s || '').replace(/'/g, "''").trim();
}
function timeToDays(s) {
  if (s === undefined || s === null) return 'NULL::numeric';
  const str = String(s).trim();
  if (!str) return 'NULL::numeric';
  const m = str.match(/^(\d+):(\d{2})$/);
  if (!m) return 'NULL::numeric';
  return Math.round(((parseInt(m[1]) + parseInt(m[2]) / 60) / 24) * 10000) / 10000;
}

// --- Buscar rango de fechas ---
let dateMatch = null;
for (let i = 0; i < Math.min(allItems.length, 15); i++) {
  for (let c = 0; c < Math.min(repKeysLen, 5); c++) {
    const val = String(getCol(allItems[i], c) || '');
    const m = val.match(/Fecha inicial:\s*(\d{2})\/(\d{2})\/(\d{4})\s+Fecha final:\s*(\d{2})\/(\d{2})\/(\d{4})/);
    if (m) { dateMatch = m; break; }
  }
  if (dateMatch) break;
}

if (!dateMatch) {
  return [{ json: { valid: false, errorMessage: 'No se encontro rango de fechas en ' + fileName + '. Verifique que sea un archivo de tiempos de entrega exportado de Enterprise.' } }];
}

const fechaInicio = dateMatch[3] + '-' + dateMatch[2] + '-' + dateMatch[1];
const fechaFin = dateMatch[6] + '-' + dateMatch[5] + '-' + dateMatch[4];
const anio = parseInt(dateMatch[3]);
const mesNum = parseInt(dateMatch[2]);
const meses = ['','ENE','FEB','MAR','ABR','MAY','JUN','JUL','AGO','SEP','OCT','NOV','DIC'];
const mes = meses[mesNum];

// --- Encontrar inicio de la seccion ---
let secStart = -1;
for (let i = 0; i < Math.min(allItems.length, 20); i++) {
  const v = String(getCol(allItems[i], 0) || '').trim();
  if (/secci[oó]n/i.test(v)) { secStart = i + 1; break; }
}
if (secStart < 0) {
  for (let i = 2; i < Math.min(allItems.length, 20); i++) {
    const c0 = String(getCol(allItems[i], 0) || '').trim();
    const c1 = getCol(allItems[i], 1);
    if (c0.length > 2 && !isNaN(parseInt(c1)) && parseInt(c1) > 0) { secStart = i; break; }
  }
}
if (secStart < 0) secStart = 5;

const secNameRaw = String(getCol(allItems[secStart], 0) || '').trim();
if (!secNameRaw) {
  return [{ json: { valid: false, errorMessage: 'No se encontro nombre de seccion en ' + fileName } }];
}
const seccionPadre = secNameRaw.replace(/\s+$/, '');

const secTotal = parseInt(getCol(allItems[secStart], 1)) || 0;
const secIngRes = String(getCol(allItems[secStart], 2) || '').trim();
const secResVal = String(getCol(allItems[secStart], 3) || '').trim();
const secIngVal = String(getCol(allItems[secStart], 4) || '').trim();
const secValImp = String(getCol(allItems[secStart], 5) || '').trim();
const secIngImp = String(getCol(allItems[secStart], 6) || '').trim();

// --- SQL para periodo + seccion ---
const secVal = `('${esc(seccionPadre)}', ${secTotal}, '${esc(secIngRes)}', '${esc(secResVal)}', '${esc(secIngVal)}', '${esc(secValImp)}', '${esc(secIngImp)}', ${timeToDays(secIngRes)}, ${timeToDays(secResVal)}, ${timeToDays(secIngVal)}, ${timeToDays(secValImp)}, ${timeToDays(secIngImp)})`;

const sectionSQL = `
WITH new_periodo AS (
  INSERT INTO periodos (fecha_inicio, fecha_fin, mes, anio, archivo_origen)
  VALUES ('${fechaInicio}', '${fechaFin}', '${mes}', ${anio}, '${esc(fileName)}')
  ON CONFLICT (fecha_inicio, fecha_fin)
  DO UPDATE SET archivo_origen = EXCLUDED.archivo_origen
  RETURNING id
)
INSERT INTO tiempos_seccion (
  periodo_id, seccion, total_examenes,
  ingreso_resultado_horas, resultado_validacion_horas, ingreso_validacion_horas,
  validacion_impresion_horas, ingreso_impresion_horas,
  ingreso_resultado_dias, resultado_validacion_dias, ingreso_validacion_dias,
  validacion_impresion_dias, ingreso_impresion_dias,
  meta_dias, eficacia
)
SELECT
  np.id, v.seccion, v.total_examenes,
  v.ir_h, v.rv_h, v.iv_h, v.vi_h, v.ii_h,
  v.ir_d, v.rv_d, v.iv_d, v.vi_d, v.ii_d,
  m.meta_dias,
  CASE WHEN v.ii_d > 0 AND m.meta_dias IS NOT NULL AND m.meta_dias > 0
    THEN ROUND(m.meta_dias / v.ii_d, 4)
    ELSE NULL
  END
FROM new_periodo np
CROSS JOIN (VALUES
    ${secVal}
) AS v(seccion, total_examenes, ir_h, rv_h, iv_h, vi_h, ii_h, ir_d, rv_d, iv_d, vi_d, ii_d)
LEFT JOIN metas_seccion m ON UPPER(TRIM(m.seccion)) = UPPER(TRIM(v.seccion))
ON CONFLICT (periodo_id, seccion)
DO UPDATE SET
  total_examenes = EXCLUDED.total_examenes,
  ingreso_resultado_horas = EXCLUDED.ingreso_resultado_horas,
  resultado_validacion_horas = EXCLUDED.resultado_validacion_horas,
  ingreso_validacion_horas = EXCLUDED.ingreso_validacion_horas,
  validacion_impresion_horas = EXCLUDED.validacion_impresion_horas,
  ingreso_impresion_horas = EXCLUDED.ingreso_impresion_horas,
  ingreso_resultado_dias = EXCLUDED.ingreso_resultado_dias,
  resultado_validacion_dias = EXCLUDED.resultado_validacion_dias,
  ingreso_validacion_dias = EXCLUDED.ingreso_validacion_dias,
  validacion_impresion_dias = EXCLUDED.validacion_impresion_dias,
  ingreso_impresion_dias = EXCLUDED.ingreso_impresion_dias,
  meta_dias = EXCLUDED.meta_dias,
  eficacia = EXCLUDED.eficacia;
`;

// --- Extraer examenes individuales ---
let examStart = -1;
for (let i = secStart; i < allItems.length; i++) {
  const v = String(getCol(allItems[i], 0) || '').trim();
  if (/^examen$/i.test(v)) { examStart = i + 1; break; }
}

let examSQL = '';
let examCount = 0;
if (examStart > 0) {
  const examsMap = new Map();
  for (let i = examStart; i < allItems.length; i++) {
    const name = String(getCol(allItems[i], 0) || '').trim();
    if (/^total$/i.test(name)) break;
    if (!name) continue;
    const tVal = getCol(allItems[i], 1);
    if (tVal === undefined || tVal === null || String(tVal).trim() === '') continue;
    examsMap.set(name.toUpperCase(), {
      examen: name,
      total: parseInt(tVal) || 0,
      ingRes: String(getCol(allItems[i], 2) || '').trim(),
      resVal: String(getCol(allItems[i], 3) || '').trim(),
      ingVal: String(getCol(allItems[i], 4) || '').trim(),
      valImp: String(getCol(allItems[i], 5) || '').trim(),
      ingImp: String(getCol(allItems[i], 6) || '').trim()
    });
  }
  const exams = Array.from(examsMap.values());
  examCount = exams.length;
  if (exams.length > 0) {
    const examVals = exams.map(e =>
      `('${esc(seccionPadre)}', '${esc(e.examen)}', ${e.total}, '${esc(e.ingRes)}', '${esc(e.resVal)}', '${esc(e.ingVal)}', '${esc(e.valImp)}', '${esc(e.ingImp)}', ${timeToDays(e.ingRes)}, ${timeToDays(e.resVal)}, ${timeToDays(e.ingVal)}, ${timeToDays(e.valImp)}, ${timeToDays(e.ingImp)})`
    ).join(',\n      ');
    examSQL = `
WITH periodo AS (
  SELECT id FROM periodos
  WHERE fecha_inicio = '${fechaInicio}' AND fecha_fin = '${fechaFin}'
  LIMIT 1
)
INSERT INTO tiempos_examen (
  periodo_id, seccion_padre, examen, total_examenes,
  ingreso_resultado_horas, resultado_validacion_horas, ingreso_validacion_horas,
  validacion_impresion_horas, ingreso_impresion_horas,
  ingreso_resultado_dias, resultado_validacion_dias, ingreso_validacion_dias,
  validacion_impresion_dias, ingreso_impresion_dias
)
SELECT
  p.id, v.seccion_padre, v.examen, v.total_examenes,
  v.ir_h, v.rv_h, v.iv_h, v.vi_h, v.ii_h,
  v.ir_d, v.rv_d, v.iv_d, v.vi_d, v.ii_d
FROM periodo p
CROSS JOIN (VALUES
      ${examVals}
) AS v(seccion_padre, examen, total_examenes, ir_h, rv_h, iv_h, vi_h, ii_h, ir_d, rv_d, iv_d, vi_d, ii_d);
`;
  }
}

// --- Borrar examenes previos de ESTA SECCION ---
const deleteExamsSQL = `
DELETE FROM tiempos_examen
WHERE periodo_id = (
  SELECT id FROM periodos
  WHERE fecha_inicio = '${fechaInicio}' AND fecha_fin = '${fechaFin}'
)
AND UPPER(TRIM(seccion_padre)) = UPPER(TRIM('${esc(seccionPadre)}'));
`;

// --- Build response info ---
const info = {
  seccion: seccionPadre,
  periodo: mes + ' ' + anio,
  totalExamenes: examCount,
  fileName: fileName
};

// --- Retornar queries ---
const output = [
  { json: { valid: true, query: sectionSQL, info: info } }
];
if (examSQL) {
  output.push({ json: { valid: true, query: deleteExamsSQL } });
  output.push({ json: { valid: true, query: examSQL } });
}
return output;

} catch (err) {
  return [{ json: { valid: false, errorMessage: 'Error procesando archivo: ' + err.message } }];
}

const info = $('Validar y Transformar').first().json.info || {};
return [{ json: {
  success: true,
  message: 'Procesado: ' + (info.seccion || 'seccion') + ' - ' + (info.totalExamenes || 0) + ' examenes - ' + (info.periodo || ''),
  details: info
}}];

const errorMsg = $input.first().json.errorMessage || 'Error desconocido';
return [{ json: {
  success: false,
  message: errorMsg
}}];
